// ACU预设同步 - 跨设备共享骰子系统预设
eventOn(getButtonEvent('上传'), () => {
  var d = {
    presets: localStorage.getItem('acu_advanced_presets_v1') || '',
    attr: localStorage.getItem('acu_attribute_presets_v1') || ''
  };
  insertOrAssignVariables({ acu_sync_data: d }, { type: 'global' });
  console.log('[ACU同步] 已上传');
});
eventOn(getButtonEvent('下载'), () => {
  var v = getVariables({ type: 'global' });
  if (v && v.acu_sync_data) {
    if (v.acu_sync_data.presets) localStorage.setItem('acu_advanced_presets_v1', v.acu_sync_data.presets);
    if (v.acu_sync_data.attr) localStorage.setItem('acu_attribute_presets_v1', v.acu_sync_data.attr);
    console.log('[ACU同步] 已下载，请刷新页面');
    location.reload();
  }
});
